// // This module is designed to asynchronously capture an 8-bit input data 'd' on the falling edge of a clock signal 'clk' and output it as an 8-bit value 'q'.
module top_module(
    input clk,
    input [7:0] d,
    output [7:0] q
);reg [7:0] q_reg;
always @(posedge clk)begin
    q_reg <= d;
end

assign q = q_reg;



endmodule
